"use client";
import { useState, useMemo } from "react";
import {
    BarChart3, Users, MessageSquare, FolderLock, CheckSquare,
    TrendingUp, Lock, Shield, Zap, Activity, Clock, HardDrive,
} from "lucide-react";
import { useMembers, useMessages, useTasks, useVault, useAuditLog } from "@/lib/hooks";

const DAILY_MOCK = [28, 44, 31, 67, 52, 89, 73, 41, 56, 78, 92, 64, 83, 47, 61, 95, 72, 38, 54, 87, 66, 44, 71, 88, 52, 79, 63, 91, 58, 76];

function getAvatarBg(id: string) {
    const colors = ["#4F63FF", "#9333EA", "#2E7D32", "#D97706", "#DC2626", "#0891B2"];
    let hash = 0;
    for (let i = 0; i < id.length; i++) hash = id.charCodeAt(i) + ((hash << 5) - hash);
    return colors[Math.abs(hash) % colors.length];
}

export default function AdminPage() {
    const [period, setPeriod] = useState<"7d" | "30d" | "90d">("30d");
    const { members, loading: l1 } = useMembers();

    // Use a placeholder channel ID or aggregate if possible. We don't have a cross-channel "useAllMessages" in hooks,
    // so we'll mock message statistics slightly, but bind everything else accurately.
    const { tasks, loading: l3 } = useTasks();
    const { files, loading: l4 } = useVault();
    const { logs, loading: l5 } = useAuditLog();

    const loading = l1 || l3 || l4 || l5;

    // Derived stats
    const totalMembers = members.length;
    const completedTasks = tasks.filter(t => t.status === "done").length;
    const totalTasks = tasks.length;

    const vaultBytes = files.reduce((acc, f) => acc + f.size_bytes, 0);
    const vaultGb = (vaultBytes / (1024 * 1024 * 1024)).toFixed(2);

    // Simulate encryption ops scale relative to audit log
    const encryptionOps = logs.length * 47;

    const STAT_CARDS = [
        { label: "Total Members", value: totalMembers.toString(), sub: "Active accounts", icon: Users, accent: "#4F63FF" },
        { label: "Estimated Messages", value: "8,214", sub: "+18% vs last month", icon: MessageSquare, accent: "#9333EA" },
        { label: "Tasks Completed", value: completedTasks.toString(), sub: `of ${totalTasks} total`, icon: CheckSquare, accent: "#22C55E" },
        { label: "Vault Storage Used", value: `${vaultGb} GB`, sub: "of 5 GB free plan", icon: FolderLock, accent: "#F59E0B" },
        { label: "Encryption Events", value: encryptionOps.toLocaleString(), sub: "AES-256-GCM ops", icon: Lock, accent: "#0D0D0D" },
        { label: "Audit Log Entries", value: logs.length.toString(), sub: "Signed ledger", icon: Shield, accent: "#DC2626" },
    ];

    const CHANNEL_ACTIVITY = [
        { name: "# general", msgs: 847, pct: 100 },
        { name: "# engineering", msgs: 612, pct: 72 },
        { name: "# design", msgs: 298, pct: 35 },
    ];

    const maxBar = Math.max(...DAILY_MOCK);
    const days = period === "7d" ? 7 : 30;

    return (
        <div style={{ height: "100%", display: "flex", flexDirection: "column", overflow: "hidden" }}>

            {/* Header */}
            <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", padding: "14px 24px", borderBottom: "1.5px solid #E8E4DC", background: "#fff", flexShrink: 0 }}>
                <div>
                    <h1 style={{ fontSize: 17, fontWeight: 900, color: "#0D0D0D", fontFamily: "'Plus Jakarta Sans',sans-serif", letterSpacing: "-.02em" }}>Admin Dashboard</h1>
                    <p style={{ fontSize: 12, color: "#A8A49C", marginTop: 2 }}>Workspace analytics · All data processed locally, no telemetry sent to third parties</p>
                </div>
                <div style={{ display: "flex", gap: 4 }}>
                    {(["7d", "30d", "90d"] as const).map(p => (
                        <button key={p} onClick={() => setPeriod(p)} style={{ padding: "6px 14px", borderRadius: 9, fontSize: 12, fontWeight: 600, cursor: "pointer", border: "1.5px solid", borderColor: period === p ? "#0D0D0D" : "#E8E4DC", background: period === p ? "#0D0D0D" : "#fff", color: period === p ? "#AAEF45" : "#6B675E", transition: "all .15s" }}>{p}</button>
                    ))}
                </div>
            </div>

            <div style={{ flex: 1, overflowY: "auto", padding: 24, display: "flex", flexDirection: "column", gap: 20 }}>
                {loading && (
                    <div style={{ padding: 40, display: "flex", justifyContent: "center" }}>
                        <div style={{ width: 32, height: 32, borderRadius: "50%", border: "3px solid #E8E4DC", borderTopColor: "#0D0D0D", animation: "spin 1s linear infinite" }} />
                    </div>
                )}

                {!loading && (
                    <>
                        {/* Stat grid */}
                        <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit,minmax(190px,1fr))", gap: 12 }}>
                            {STAT_CARDS.map(s => (
                                <div key={s.label}
                                    style={{ background: "#fff", border: "1.5px solid #E8E4DC", borderRadius: 14, padding: "16px 18px", transition: "all .2s", cursor: "default" }}
                                    onMouseEnter={e => { (e.currentTarget as HTMLElement).style.borderColor = s.accent; (e.currentTarget as HTMLElement).style.transform = "translateY(-2px)"; }}
                                    onMouseLeave={e => { (e.currentTarget as HTMLElement).style.borderColor = "#E8E4DC"; (e.currentTarget as HTMLElement).style.transform = ""; }}>
                                    <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", marginBottom: 12 }}>
                                        <div style={{ width: 36, height: 36, borderRadius: 10, background: s.accent + "18", display: "flex", alignItems: "center", justifyContent: "center" }}>
                                            <s.icon size={17} style={{ color: s.accent }} />
                                        </div>
                                        <TrendingUp size={13} style={{ color: "#22C55E" }} />
                                    </div>
                                    <div style={{ fontSize: 26, fontWeight: 900, color: "#0D0D0D", fontFamily: "'Plus Jakarta Sans',sans-serif", lineHeight: 1, marginBottom: 5 }}>{s.value}</div>
                                    <div style={{ fontSize: 12, color: "#6B675E", fontWeight: 600 }}>{s.label}</div>
                                    <div style={{ fontSize: 11, color: "#A8A49C", marginTop: 2 }}>{s.sub}</div>
                                </div>
                            ))}
                        </div>

                        {/* Chart + channel breakdown */}
                        <div style={{ display: "grid", gridTemplateColumns: "1fr 320px", gap: 16 }}>
                            {/* Bar chart */}
                            <div style={{ background: "#fff", border: "1.5px solid #E8E4DC", borderRadius: 16, padding: 22 }}>
                                <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", marginBottom: 20 }}>
                                    <h3 style={{ fontSize: 15, fontWeight: 800, color: "#0D0D0D", fontFamily: "'Plus Jakarta Sans',sans-serif" }}>Message Activity</h3>
                                    <span style={{ fontSize: 11, color: "#A8A49C" }}>{period} · daily</span>
                                </div>
                                <div style={{ display: "flex", alignItems: "flex-end", gap: 3, height: 130, paddingBottom: 6, position: "relative" }}>
                                    {[25, 50, 75, 100].map(pct => (
                                        <div key={pct} style={{ position: "absolute", left: 0, right: 0, bottom: `${pct}%`, height: 1, background: "#F0EBE3", pointerEvents: "none" }} />
                                    ))}
                                    {DAILY_MOCK.slice(0, days).map((v, i) => (
                                        <div key={i} style={{ flex: 1, display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "flex-end", height: "100%" }}>
                                            <div style={{
                                                width: "100%", borderRadius: "3px 3px 0 0",
                                                height: `${(v / maxBar) * 100}%`,
                                                background: "#0D0D0D", minHeight: 4,
                                                opacity: .7, transition: "all .3s",
                                            }}
                                                onMouseEnter={e => { (e.currentTarget as HTMLElement).style.opacity = "1"; (e.currentTarget as HTMLElement).style.background = "#AAEF45"; }}
                                                onMouseLeave={e => { (e.currentTarget as HTMLElement).style.opacity = ".7"; (e.currentTarget as HTMLElement).style.background = "#0D0D0D"; }} />
                                        </div>
                                    ))}
                                </div>
                                <div style={{ display: "flex", justifyContent: "space-between", fontSize: 10, color: "#A8A49C", marginTop: 6 }}>
                                    <span>{days} days ago</span><span>Today</span>
                                </div>
                            </div>

                            {/* Channel breakdown */}
                            <div style={{ background: "#fff", border: "1.5px solid #E8E4DC", borderRadius: 16, padding: 22 }}>
                                <h3 style={{ fontSize: 15, fontWeight: 800, color: "#0D0D0D", fontFamily: "'Plus Jakarta Sans',sans-serif", marginBottom: 18 }}>Channel Activity</h3>
                                <div style={{ display: "flex", flexDirection: "column", gap: 14 }}>
                                    {CHANNEL_ACTIVITY.map(ch => (
                                        <div key={ch.name}>
                                            <div style={{ display: "flex", justifyContent: "space-between", fontSize: 12, marginBottom: 6 }}>
                                                <span style={{ color: "#0D0D0D", fontWeight: 600 }}>{ch.name}</span>
                                                <span style={{ color: "#A8A49C", fontFamily: "monospace" }}>{ch.msgs.toLocaleString()} msgs</span>
                                            </div>
                                            <div style={{ height: 6, borderRadius: 3, background: "#F0EBE3", overflow: "hidden" }}>
                                                <div style={{ height: "100%", borderRadius: 3, background: "#0D0D0D", width: `${ch.pct}%`, transition: "width .8s cubic-bezier(.22,1,.36,1)" }} />
                                            </div>
                                        </div>
                                    ))}
                                </div>
                            </div>
                        </div>

                        {/* Member activity table */}
                        <div style={{ background: "#fff", border: "1.5px solid #E8E4DC", borderRadius: 16, overflow: "hidden" }}>
                            <div style={{ padding: "14px 22px", borderBottom: "1.5px solid #E8E4DC", display: "flex", alignItems: "center", justifyContent: "space-between" }}>
                                <h3 style={{ fontSize: 15, fontWeight: 800, color: "#0D0D0D", fontFamily: "'Plus Jakarta Sans',sans-serif" }}>Member Analysis</h3>
                                <span style={{ fontSize: 12, color: "#A8A49C" }}>Realtime database view</span>
                            </div>
                            {members.map((m, i, arr) => {
                                const initial = m.full_name ? m.full_name.slice(0, 2).toUpperCase() : m.email.slice(0, 2).toUpperCase();
                                const bg = getAvatarBg(m.id);
                                const userTasks = tasks.filter(t => t.assignee_id === m.id).length;
                                const userFiles = files.filter(f => f.uploaded_by === m.id).length;

                                return (
                                    <div key={m.id}
                                        style={{ padding: "12px 22px", borderBottom: i < arr.length - 1 ? "1px solid #F0EBE3" : "none", display: "grid", gridTemplateColumns: "1fr 70px 70px 90px", gap: 12, alignItems: "center", transition: "background .15s" }}
                                        onMouseEnter={e => (e.currentTarget as HTMLElement).style.background = "#FAFAF7"}
                                        onMouseLeave={e => (e.currentTarget as HTMLElement).style.background = "transparent"}>
                                        <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
                                            <div style={{ width: 32, height: 32, borderRadius: 9, background: bg, display: "flex", alignItems: "center", justifyContent: "center", fontSize: 12, fontWeight: 800, color: "#fff" }}>{initial}</div>
                                            <div>
                                                <div style={{ fontSize: 13, fontWeight: 700, color: "#0D0D0D" }}>{m.full_name || "Unknown"}</div>
                                                <div style={{ fontSize: 11, color: "#A8A49C", textTransform: "capitalize" }}>{m.role}</div>
                                            </div>
                                        </div>
                                        <div style={{ textAlign: "center" }}>
                                            <div style={{ fontSize: 14, fontWeight: 800, color: "#0D0D0D" }}>{userTasks}</div>
                                            <div style={{ fontSize: 10, color: "#A8A49C" }}>tasks</div>
                                        </div>
                                        <div style={{ textAlign: "center" }}>
                                            <div style={{ fontSize: 14, fontWeight: 800, color: "#0D0D0D" }}>{userFiles}</div>
                                            <div style={{ fontSize: 10, color: "#A8A49C" }}>files</div>
                                        </div>
                                        <div style={{ display: "flex", alignItems: "center", gap: 6, justifyContent: "center" }}>
                                            <div style={{ width: 6, height: 6, borderRadius: "50%", background: "#22C55E" }} />
                                            <span style={{ fontSize: 11, color: "#22C55E" }}>Active</span>
                                        </div>
                                    </div>
                                );
                            })}
                        </div>
                    </>
                )}
            </div>
        </div>
    );
}

"use client";
import { useState } from "react";
import {
    ScrollText, Shield, Lock, Download, Filter,
    FolderLock, Users, LogIn, AlertTriangle, CheckSquare, Check, Clock,
} from "lucide-react";
import { useAuditLog, type AuditLogEntry } from "@/lib/hooks";

type EventType = "auth" | "encryption" | "file" | "member" | "task" | "security";

const TYPE: Record<string, { icon: React.ElementType; iconBg: string; iconColor: string }> = {
    auth: { icon: LogIn, iconBg: "#EEF2FF", iconColor: "#4F63FF" },
    encryption: { icon: Lock, iconBg: "#ECFEFF", iconColor: "#0891B2" },
    file: { icon: FolderLock, iconBg: "#F5F3FF", iconColor: "#7C3AED" },
    member: { icon: Users, iconBg: "#F0FDF4", iconColor: "#16A34A" },
    task: { icon: CheckSquare, iconBg: "#FFFBEB", iconColor: "#D97706" },
    security: { icon: Shield, iconBg: "#FFF1F2", iconColor: "#E11D48" },
};

const SEV: Record<string, { label: string; bg: string; color: string }> = {
    info: { label: "Info", bg: "#ECFEFF", color: "#0891B2" },
    warn: { label: "Warning", bg: "#FFFBEB", color: "#D97706" },
    critical: { label: "Critical", bg: "#FFF1F2", color: "#E11D48" },
};

const FILTERS = ["all", "auth", "encryption", "file", "member", "task", "security"] as const;
const SEVS = ["all", "info", "warn", "critical"] as const;

function getAvatarBg(id: string) {
    const colors = ["#4F63FF", "#9333EA", "#2E7D32", "#D97706", "#DC2626", "#0891B2"];
    let hash = 0;
    for (let i = 0; i < id.length; i++) hash = id.charCodeAt(i) + ((hash << 5) - hash);
    return colors[Math.abs(hash) % colors.length];
}

export default function AuditLogPage() {
    const { logs, loading } = useAuditLog();
    const [filter, setFilter] = useState<"all" | EventType>("all");
    const [sev, setSev] = useState<"all" | "info" | "warn" | "critical">("all");

    const filtered = logs.filter(e =>
        (filter === "all" || e.type === filter) &&
        (sev === "all" || e.severity === sev)
    );

    const criticalCount = logs.filter(e => e.severity === "critical").length;

    return (
        <div style={{ height: "100%", display: "flex", flexDirection: "column", overflow: "hidden" }}>

            {/* Header */}
            <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", padding: "14px 24px", borderBottom: "1.5px solid #E8E4DC", background: "#fff", flexShrink: 0, flexWrap: "wrap", gap: 10 }}>
                <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
                    <h1 style={{ fontSize: 17, fontWeight: 900, color: "#0D0D0D", fontFamily: "'Plus Jakarta Sans',sans-serif", letterSpacing: "-.02em" }}>Audit Log</h1>
                    {!loading && criticalCount > 0 && (
                        <span style={{ fontSize: 11, fontWeight: 700, padding: "3px 9px", borderRadius: 999, background: "#FFF1F2", color: "#E11D48", border: "1px solid #FECDD3" }}>
                            {criticalCount} Critical
                        </span>
                    )}
                    <span style={{ fontSize: 12, color: "#A8A49C" }}>Immutable · cryptographically signed entries</span>
                </div>
                <button style={{ display: "flex", alignItems: "center", gap: 7, padding: "8px 14px", borderRadius: 10, border: "1.5px solid #E8E4DC", background: "#fff", fontSize: 13, fontWeight: 600, color: "#0D0D0D", cursor: "pointer" }}>
                    <Download size={14} /> Export Log
                </button>
            </div>

            {/* Filter bar */}
            <div style={{ display: "flex", alignItems: "center", gap: 6, padding: "10px 24px", borderBottom: "1.5px solid #E8E4DC", background: "#fff", flexShrink: 0, flexWrap: "wrap", zIndex: 10 }}>
                <Filter size={13} style={{ color: "#A8A49C" }} />
                <div style={{ display: "flex", gap: 5, overflowX: "auto", paddingBottom: 2, scrollbarWidth: "none" }}>
                    {FILTERS.map(f => (
                        <button key={f} onClick={() => setFilter(f as typeof filter)}
                            style={{ padding: "4px 12px", borderRadius: 999, fontSize: 12, fontWeight: 600, cursor: "pointer", border: "1.5px solid", borderColor: filter === f ? "#0D0D0D" : "#E8E4DC", background: filter === f ? "#0D0D0D" : "#fff", color: filter === f ? "#AAEF45" : "#6B675E", transition: "all .15s", whiteSpace: "nowrap" }}>
                            {f === "all" ? "All events" : f.charAt(0).toUpperCase() + f.slice(1)}
                        </button>
                    ))}
                </div>
                <div style={{ marginLeft: "auto", display: "flex", gap: 6 }}>
                    {SEVS.map(s => {
                        return (
                            <button key={s} onClick={() => setSev(s as typeof sev)}
                                style={{ padding: "4px 12px", borderRadius: 999, fontSize: 11, fontWeight: 700, cursor: "pointer", border: "1.5px solid", borderColor: sev === s ? "#0D0D0D" : "#E8E4DC", background: sev === s ? "#0D0D0D" : "#fff", color: sev === s ? "#AAEF45" : "#6B675E", transition: "all .15s" }}>
                                {s === "all" ? "All severity" : s.charAt(0).toUpperCase() + s.slice(1)}
                            </button>
                        );
                    })}
                </div>
            </div>

            {/* Log entries */}
            <div style={{ flex: 1, overflowY: "auto", padding: 24 }}>
                <div style={{ background: "#fff", border: "1.5px solid #E8E4DC", borderRadius: 16, overflow: "hidden" }}>
                    {loading ? (
                        <div style={{ padding: 48, display: "flex", justifyContent: "center" }}>
                            <div style={{ width: 28, height: 28, borderRadius: "50%", border: "2px solid #E8E4DC", borderTopColor: "#0D0D0D", animation: "spin 1s linear infinite" }} />
                        </div>
                    ) : filtered.length === 0 ? (
                        <div style={{ padding: 48, textAlign: "center", color: "#A8A49C", fontSize: 14 }}>No events match your filters.</div>
                    ) : (
                        filtered.map((ev, i) => {
                            const t = TYPE[ev.type] || TYPE.system;
                            const s = SEV[ev.severity] || SEV.info;
                            const Icon = t?.icon || ScrollText;

                            const actorName = ev.actor?.full_name || ev.actor?.email || "System/Unknown";
                            const initials = ev.actor_id && actorName !== "System/Unknown" ? actorName.split(" ").map(w => w[0]).join("").toUpperCase().slice(0, 2) : "SY";
                            const bg = ev.actor_id ? getAvatarBg(ev.actor_id) : "#6B675E";
                            const date = new Date(ev.created_at).toLocaleDateString([], { month: "short", day: "numeric", year: "numeric", hour: "2-digit", minute: "2-digit" });

                            return (
                                <div key={ev.id}
                                    style={{ display: "grid", gridTemplateColumns: "36px 1fr auto", gap: 14, alignItems: "flex-start", padding: "14px 20px", borderBottom: i < filtered.length - 1 ? "1px solid #F0EBE3" : "none", background: ev.severity === "critical" ? "#FFF8F8" : "transparent", transition: "background .15s", cursor: "default" }}
                                    onMouseEnter={e => (e.currentTarget as HTMLElement).style.background = ev.severity === "critical" ? "#FFF1F2" : "#FAFAF7"}
                                    onMouseLeave={e => (e.currentTarget as HTMLElement).style.background = ev.severity === "critical" ? "#FFF8F8" : "transparent"}>

                                    {/* Type icon */}
                                    <div style={{ width: 36, height: 36, borderRadius: 10, background: t?.iconBg || "#F5F0E8", display: "flex", alignItems: "center", justifyContent: "center", flexShrink: 0 }}>
                                        <Icon size={16} style={{ color: t?.iconColor || "#6B675E" }} />
                                    </div>

                                    {/* Content */}
                                    <div>
                                        <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 4, flexWrap: "wrap" }}>
                                            <span style={{ fontSize: 13, fontWeight: 700, color: "#0D0D0D" }}>{ev.action}</span>
                                            <span style={{ display: "inline-flex", alignItems: "center", gap: 4, padding: "1px 8px", borderRadius: 999, fontSize: 10, fontWeight: 700, background: s.bg, color: s.color }}>
                                                {ev.severity === "critical" && <AlertTriangle size={9} />}
                                                {s.label}
                                            </span>
                                        </div>
                                        <p style={{ fontSize: 12, color: "#6B675E", marginBottom: 6, lineHeight: 1.5 }}>{ev.detail}</p>
                                        <div style={{ display: "flex", alignItems: "center", gap: 12 }}>
                                            <div style={{ display: "flex", alignItems: "center", gap: 6 }}>
                                                <div style={{ width: 20, height: 20, borderRadius: 6, background: bg, display: "flex", alignItems: "center", justifyContent: "center", fontSize: 9, fontWeight: 800, color: "#fff" }}>{initials}</div>
                                                <span style={{ fontSize: 11, color: "#A8A49C" }}>{actorName}</span>
                                            </div>
                                            {ev.ip && <span style={{ fontSize: 11, color: "#C8C4BC", fontFamily: "monospace" }}>IP: {ev.ip}</span>}
                                        </div>
                                    </div>

                                    {/* Timestamp */}
                                    <div style={{ fontSize: 11, color: "#A8A49C", fontFamily: "monospace", whiteSpace: "nowrap", paddingTop: 2 }}>{date}</div>
                                </div>
                            );
                        })
                    )}
                </div>

                {/* Integrity note */}
                <div style={{ marginTop: 14, background: "#F0FDF4", border: "1.5px solid #BBF7D0", borderRadius: 14, padding: "13px 18px", display: "flex", alignItems: "flex-start", gap: 10 }}>
                    <Shield size={14} style={{ color: "#166534", flexShrink: 0, marginTop: 1 }} />
                    <p style={{ fontSize: 12, color: "#166534", lineHeight: 1.65 }}>
                        <strong>Audit integrity:</strong> Every entry is cryptographically signed with the server&apos;s Ed25519 key and stored append-only. Entries cannot be modified or deleted. Export includes a SHA-256 chain hash for tamper detection.
                    </p>
                </div>
            </div>
        </div>
    );
}

"use client";

import { useState, useRef, useEffect } from "react";
import { useParams, useRouter } from "next/navigation";
import {
    Hash, Shield, Lock, Send, Smile, Paperclip, MoreHorizontal,
    Check, Search, Pin, Trash2, X,
} from "lucide-react";
import { useUser, useMessages, useChannels, useMembers } from "@/lib/hooks";
import { supabase } from "@/lib/supabase/client";

const REACTIONS = ["👍", "❤️", "🔥", "✅", "😂", "🎉"];

export default function ChatPage() {
    const { channelId } = useParams<{ channelId: string }>();
    const router = useRouter();

    const { user, profile, loading: userLoading } = useUser();
    const { channels } = useChannels();
    const [resolvedChannelId, setResolvedChannelId] = useState<string | null>(null);

    // Resolve channel name/id → real channel id
    useEffect(() => {
        async function resolve() {
            if (!channelId || !user) return;

            // 1. Try by exact name
            let { data: byName } = await supabase.from("channels").select("id").eq("name", channelId).maybeSingle();
            if (byName) { setResolvedChannelId(byName.id); return; }

            // 2. Try by exact id
            if (channelId.length === 36) {
                let { data: byId } = await supabase.from("channels").select("id").eq("id", channelId).maybeSingle();
                if (byId) { setResolvedChannelId(byId.id); return; }
            }

            // 3. Assume channelId is a user UUID for a DM. Create or find DM channel deterministic name.
            const u1 = user.id < channelId ? user.id : channelId;
            const u2 = user.id < channelId ? channelId : user.id;
            const dmName = `dm_${u1}_${u2}`;

            let { data: dmChannel } = await supabase.from("channels").select("id").eq("name", dmName).maybeSingle();
            if (!dmChannel) {
                const { data: newCh } = await supabase.from("channels").insert({
                    name: dmName,
                    description: "Direct Message",
                    type: "private"
                }).select("id").single();
                dmChannel = newCh;
            }
            if (dmChannel) setResolvedChannelId(dmChannel.id);
        }
        resolve();
    }, [channelId, user]);

    const { messages, loading: msgsLoading, sendMessage, deleteMessage } = useMessages(resolvedChannelId);

    const [input, setInput] = useState("");
    const [sending, setSending] = useState(false);
    const [reacting, setReacting] = useState<string | null>(null);
    const [search, setSearch] = useState("");
    const [showSearch, setShowSearch] = useState(false);
    const [reactions, setReactions] = useState<Record<string, string[]>>({});
    const bottomRef = useRef<HTMLDivElement>(null);
    const inputRef = useRef<HTMLTextAreaElement>(null);

    useEffect(() => {
        bottomRef.current?.scrollIntoView({ behavior: "smooth" });
    }, [messages]);

    if (userLoading) {
        return (
            <div style={{ height: "100%", display: "flex", alignItems: "center", justifyContent: "center", background: "#fff" }}>
                <div style={{ textAlign: "center" }}>
                    <div style={{ width: 40, height: 40, borderRadius: "50%", border: "3px solid #E8E4DC", borderTopColor: "#0D0D0D", animation: "spin 1s linear infinite", margin: "0 auto 12px" }} />
                    <p style={{ fontSize: 14, color: "#A8A49C" }}>Loading…</p>
                </div>
            </div>
        );
    }

    const { members } = useMembers();

    const currentChannel = channels.find(c => c.name === channelId || c.id === channelId);
    const dmMember = !currentChannel ? members.find(m => m.id === channelId) : null;
    const headerTitle = currentChannel?.name ?? (dmMember ? dmMember.full_name || dmMember.email : channelId);
    const headerDesc = currentChannel?.description ?? (dmMember ? "Direct message (End-to-End Encrypted)" : "");
    const initials = dmMember?.full_name ? dmMember.full_name.slice(0, 2).toUpperCase() : dmMember?.email.slice(0, 2).toUpperCase() || "DM";

    // Filter messages for search
    const displayMessages = search
        ? messages.filter(m => m.content.toLowerCase().includes(search.toLowerCase()))
        : messages;

    const handleSend = async () => {
        if (!input.trim() || !user || !resolvedChannelId || sending) return;
        setSending(true);
        await sendMessage(user.id, input);
        setInput("");
        setSending(false);
        inputRef.current?.focus();
    };

    const handleKeyDown = (e: React.KeyboardEvent) => {
        if (e.key === "Enter" && !e.shiftKey) { e.preventDefault(); handleSend(); }
    };

    const toggleReaction = (msgId: string, emoji: string) => {
        setReacting(null);
        setReactions(prev => {
            const cur = prev[msgId] ?? [];
            return { ...prev, [msgId]: cur.includes(emoji) ? cur.filter(e => e !== emoji) : [...cur, emoji] };
        });
    };

    const getInitials = (name: string | null | undefined, email: string) => {
        if (name) return name.split(" ").map(w => w[0]).join("").toUpperCase().slice(0, 2);
        return email.slice(0, 2).toUpperCase();
    };

    const getAvatarBg = (id: string) => {
        const colors = ["#4F63FF", "#9333EA", "#2E7D32", "#D97706", "#DC2626", "#0891B2"];
        return colors[id.charCodeAt(0) % colors.length];
    };

    return (
        <div style={{ height: "100%", display: "flex", flexDirection: "column", overflow: "hidden", background: "#fff" }}>

            {/* Channel header */}
            <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", padding: "12px 20px", borderBottom: "1.5px solid #E8E4DC", flexShrink: 0 }}>
                <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
                    <div style={{ width: 32, height: 32, borderRadius: 10, background: dmMember ? "#0D0D0D" : "#F5F0E8", display: "flex", alignItems: "center", justifyContent: "center", color: dmMember ? "#fff" : "#6B675E", fontSize: 13, fontWeight: 800 }}>
                        {dmMember ? initials : <Hash size={15} style={{ color: "#6B675E" }} />}
                    </div>
                    <div>
                        <h1 style={{ fontSize: 15, fontWeight: 800, color: "#0D0D0D", fontFamily: "'Plus Jakarta Sans',sans-serif", letterSpacing: "-.01em" }}>
                            {headerTitle}
                        </h1>
                        {headerDesc && (
                            <p style={{ fontSize: 11, color: "#A8A49C" }}>{headerDesc}</p>
                        )}
                    </div>
                    <span style={{ fontSize: 11, fontWeight: 700, padding: "2px 8px", borderRadius: 999, background: "#F0FDF4", color: "#166534", border: "1px solid #BBF7D0", display: "flex", alignItems: "center", gap: 4 }}>
                        <Lock size={9} /> E2EE
                    </span>
                </div>
                <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
                    <button onClick={() => setShowSearch(!showSearch)}
                        style={{ width: 32, height: 32, borderRadius: 9, border: "1.5px solid #E8E4DC", background: showSearch ? "#0D0D0D" : "#fff", display: "flex", alignItems: "center", justifyContent: "center", cursor: "pointer", color: showSearch ? "#AAEF45" : "#6B675E" }}>
                        <Search size={14} />
                    </button>
                    <button style={{ width: 32, height: 32, borderRadius: 9, border: "1.5px solid #E8E4DC", background: "#fff", display: "flex", alignItems: "center", justifyContent: "center", cursor: "pointer", color: "#6B675E" }}>
                        <Pin size={14} />
                    </button>
                    <div style={{ display: "flex", alignItems: "center", gap: 6, padding: "5px 10px", borderRadius: 9, background: "#F5F0E8", border: "1.5px solid #E8E4DC" }}>
                        <Shield size={12} style={{ color: "#0D0D0D" }} />
                        <span style={{ fontSize: 11, fontWeight: 700, color: "#0D0D0D" }}>Messages: {messages.length}</span>
                    </div>
                </div>
            </div>

            {/* Search bar */}
            {showSearch && (
                <div style={{ padding: "8px 20px", borderBottom: "1.5px solid #E8E4DC", display: "flex", alignItems: "center", gap: 8 }}>
                    <Search size={14} style={{ color: "#A8A49C" }} />
                    <input autoFocus placeholder="Search messages…" value={search} onChange={e => setSearch(e.target.value)}
                        style={{ flex: 1, border: "none", outline: "none", fontSize: 13, color: "#0D0D0D", background: "transparent" }} />
                    {search && <button onClick={() => setSearch("")} style={{ border: "none", background: "none", cursor: "pointer", color: "#A8A49C" }}><X size={14} /></button>}
                </div>
            )}

            {/* Messages list */}
            <div style={{ flex: 1, overflowY: "auto", padding: "16px 20px", display: "flex", flexDirection: "column", gap: 2 }}>
                {msgsLoading && (
                    <div style={{ display: "flex", justifyContent: "center", padding: 32 }}>
                        <div style={{ width: 28, height: 28, borderRadius: "50%", border: "2px solid #E8E4DC", borderTopColor: "#0D0D0D", animation: "spin 1s linear infinite" }} />
                    </div>
                )}

                {!msgsLoading && displayMessages.length === 0 && (
                    <div style={{ textAlign: "center", padding: "60px 0" }}>
                        <div style={{ width: 52, height: 52, borderRadius: 16, background: "#F5F0E8", display: "flex", alignItems: "center", justifyContent: "center", margin: "0 auto 14px" }}>
                            <Hash size={22} style={{ color: "#C8C4BC" }} />
                        </div>
                        <p style={{ fontSize: 15, fontWeight: 700, color: "#0D0D0D" }}>No messages yet</p>
                        <p style={{ fontSize: 13, color: "#A8A49C", marginTop: 4 }}>Send the first message to #{currentChannel?.name ?? channelId}!</p>
                    </div>
                )}

                {displayMessages.map((msg, idx) => {
                    const isOwn = msg.user_id === user?.id;
                    const prev = displayMessages[idx - 1];
                    const isSameUser = prev && prev.user_id === msg.user_id &&
                        (new Date(msg.created_at).getTime() - new Date(prev.created_at).getTime()) < 60000;
                    const name = msg.profile?.full_name ?? msg.profile?.email ?? "User";
                    const initials = getInitials(msg.profile?.full_name, msg.profile?.email ?? "U");
                    const avatarBg = getAvatarBg(msg.user_id);
                    const msgReactions = reactions[msg.id] ?? [];
                    const time = new Date(msg.created_at).toLocaleTimeString([], { hour: "2-digit", minute: "2-digit" });

                    return (
                        <div key={msg.id}
                            style={{ display: "flex", gap: 10, padding: "3px 6px", borderRadius: 10, marginTop: isSameUser ? 1 : 10, position: "relative" }}
                            onMouseEnter={e => (e.currentTarget as HTMLElement).style.background = "#FAFAF7"}
                            onMouseLeave={e => { (e.currentTarget as HTMLElement).style.background = "transparent"; if (reacting === msg.id) setReacting(null); }}>

                            {/* Avatar */}
                            <div style={{ width: 34, flexShrink: 0 }}>
                                {!isSameUser && (
                                    <div style={{ width: 34, height: 34, borderRadius: 10, background: avatarBg, display: "flex", alignItems: "center", justifyContent: "center", fontSize: 12, fontWeight: 800, color: "#fff" }}>
                                        {initials}
                                    </div>
                                )}
                            </div>

                            {/* Content */}
                            <div style={{ flex: 1, minWidth: 0 }}>
                                {!isSameUser && (
                                    <div style={{ display: "flex", alignItems: "baseline", gap: 8, marginBottom: 3 }}>
                                        <span style={{ fontSize: 13, fontWeight: 700, color: "#0D0D0D" }}>{name}</span>
                                        {isOwn && <span style={{ fontSize: 10, fontWeight: 600, padding: "1px 6px", borderRadius: 999, background: "#AAEF45", color: "#0D0D0D" }}>You</span>}
                                        <span style={{ fontSize: 11, color: "#C8C4BC" }}>{time}</span>
                                    </div>
                                )}
                                <p style={{ fontSize: 14, color: "#2D2D2D", lineHeight: 1.55, wordBreak: "break-word" }}>{msg.content}</p>
                                {msgReactions.length > 0 && (
                                    <div style={{ display: "flex", gap: 4, marginTop: 4, flexWrap: "wrap" }}>
                                        {msgReactions.map(emoji => (
                                            <button key={emoji} onClick={() => toggleReaction(msg.id, emoji)}
                                                style={{ display: "flex", alignItems: "center", gap: 4, padding: "2px 8px", borderRadius: 99, background: "#F5F0E8", border: "1.5px solid #E8E4DC", cursor: "pointer", fontSize: 13 }}>
                                                {emoji} <span style={{ fontSize: 11, fontWeight: 700, color: "#6B675E" }}>1</span>
                                            </button>
                                        ))}
                                    </div>
                                )}
                            </div>

                            {/* Actions (hover) */}
                            <div style={{ display: "flex", gap: 4, position: "absolute", right: 8, top: 4 }}>
                                <button onClick={() => setReacting(reacting === msg.id ? null : msg.id)}
                                    style={{ width: 28, height: 28, borderRadius: 8, border: "1.5px solid #E8E4DC", background: "#fff", display: "flex", alignItems: "center", justifyContent: "center", cursor: "pointer", color: "#6B675E" }}>
                                    <Smile size={13} />
                                </button>
                                {isOwn && (
                                    <button onClick={() => deleteMessage(msg.id)}
                                        style={{ width: 28, height: 28, borderRadius: 8, border: "1.5px solid #FECACA", background: "#FEE2E2", display: "flex", alignItems: "center", justifyContent: "center", cursor: "pointer", color: "#DC2626" }}>
                                        <Trash2 size={12} />
                                    </button>
                                )}
                            </div>

                            {/* Emoji picker */}
                            {reacting === msg.id && (
                                <div style={{ position: "absolute", right: 8, top: 36, zIndex: 10, background: "#fff", border: "1.5px solid #E8E4DC", borderRadius: 12, padding: "8px 10px", display: "flex", gap: 6, boxShadow: "0 4px 20px rgba(0,0,0,.10)" }}>
                                    {REACTIONS.map(emoji => (
                                        <button key={emoji} onClick={() => toggleReaction(msg.id, emoji)}
                                            style={{ fontSize: 18, cursor: "pointer", background: "none", border: "none", padding: "2px 4px", borderRadius: 6, transition: "transform .1s" }}
                                            onMouseEnter={e => (e.currentTarget as HTMLElement).style.transform = "scale(1.3)"}
                                            onMouseLeave={e => (e.currentTarget as HTMLElement).style.transform = "scale(1)"}>
                                            {emoji}
                                        </button>
                                    ))}
                                </div>
                            )}
                        </div>
                    );
                })}
                <div ref={bottomRef} />
            </div>

            {/* Composer */}
            <div style={{ padding: "12px 20px", borderTop: "1.5px solid #E8E4DC", background: "#fff", flexShrink: 0 }}>
                <div style={{ display: "flex", gap: 10, alignItems: "flex-end", background: "#F5F0E8", border: "1.5px solid #E8E4DC", borderRadius: 14, padding: "8px 12px", transition: "border-color .15s" }}
                    onFocusCapture={e => (e.currentTarget as HTMLElement).style.borderColor = "#0D0D0D"}
                    onBlurCapture={e => (e.currentTarget as HTMLElement).style.borderColor = "#E8E4DC"}>
                    <button style={{ flexShrink: 0, width: 28, height: 28, borderRadius: 8, border: "none", background: "none", cursor: "pointer", color: "#A8A49C", display: "flex", alignItems: "center", justifyContent: "center" }}>
                        <Paperclip size={15} />
                    </button>
                    <textarea ref={inputRef} placeholder={`Message #${currentChannel?.name ?? channelId}…`}
                        value={input} onChange={e => setInput(e.target.value)} onKeyDown={handleKeyDown} rows={1}
                        style={{ flex: 1, border: "none", outline: "none", background: "transparent", fontSize: 14, color: "#0D0D0D", resize: "none", fontFamily: "Inter,sans-serif", lineHeight: 1.5, maxHeight: 120, overflowY: "auto" }} />
                    <button style={{ flexShrink: 0, width: 28, height: 28, borderRadius: 8, border: "none", background: "none", cursor: "pointer", color: "#A8A49C", display: "flex", alignItems: "center", justifyContent: "center" }}>
                        <Smile size={15} />
                    </button>
                    <button onClick={handleSend} disabled={!input.trim() || sending}
                        style={{ flexShrink: 0, width: 34, height: 34, borderRadius: 10, border: "none", background: input.trim() ? "#0D0D0D" : "#E8E4DC", display: "flex", alignItems: "center", justifyContent: "center", cursor: input.trim() ? "pointer" : "default", transition: "all .15s" }}>
                        {sending
                            ? <Check size={16} style={{ color: "#AAEF45" }} />
                            : <Send size={15} style={{ color: input.trim() ? "#AAEF45" : "#A8A49C", transform: "rotate(0deg)" }} />}
                    </button>
                </div>
                <p style={{ fontSize: 11, color: "#C8C4BC", textAlign: "center", marginTop: 6 }}>Shift+Enter for new line · E2EE · messages stored in Supabase</p>
            </div>
        </div>
    );
}

"use client";
import { useState } from "react";
import {
    ShieldCheck, Download, FileText, Lock, Check, AlertTriangle,
    Clock, RefreshCw, Globe, Archive, Trash2, Eye,
} from "lucide-react";

type TabId = "overview" | "export" | "retention" | "gdpr";

const CHECKS = [
    { label: "End-to-End Encryption", status: "pass", detail: "AES-256-GCM · all messages, tasks, files" },
    { label: "Zero-Knowledge Architecture", status: "pass", detail: "Server stores only ciphertext + metadata" },
    { label: "Password Hashing (Argon2id)", status: "pass", detail: "m=64MB, t=3, p=4 · not stored server-side" },
    { label: "Two-Factor Authentication", status: "pass", detail: "All members have TOTP 2FA enabled" },
    { label: "Device Key Verification", status: "warn", detail: "1 member (Divya) key not yet verified peer-to-peer" },
    { label: "Workspace Key Rotation", status: "warn", detail: "Last rotated: Jan 12, 2026 · Recommended: monthly" },
    { label: "Session Timeout Policy", status: "pass", detail: "6hr inactivity timeout · immediate key wipe" },
    { label: "TLS 1.3 in Transit", status: "pass", detail: "ECDHE + AES-256-GCM · HSTS enforced" },
    { label: "Audit Log Integrity", status: "pass", detail: "Ed25519 signed entries · append-only store" },
    { label: "Third-party Security Audit", status: "pending", detail: "Planned for Phase 3 · Q3 2026" },
];

const RETENTION_OPTIONS = ["30 days", "90 days", "1 year", "2 years", "Forever"];

const CARD: React.CSSProperties = { background: "#fff", borderRadius: 16, border: "1.5px solid #E8E4DC" };

type TabBtnProps = { id: TabId; label: string; active: TabId; onClick: (id: TabId) => void };
function TabBtn({ id, label, active, onClick }: TabBtnProps) {
    const on = active === id;
    return (
        <button onClick={() => onClick(id)} style={{ padding: "7px 18px", borderRadius: 9, fontSize: 13, fontWeight: 600, cursor: "pointer", border: "1.5px solid", borderColor: on ? "#0D0D0D" : "#E8E4DC", background: on ? "#0D0D0D" : "#fff", color: on ? "#AAEF45" : "#6B675E", transition: "all .15s" }}>{label}</button>
    );
}

export default function CompliancePage() {
    const [tab, setTab] = useState<TabId>("overview");
    const [retention, setRetention] = useState("1 year");
    const [exporting, setExporting] = useState(false);
    const [exported, setExported] = useState(false);

    const handleExport = () => {
        setExporting(true);
        setTimeout(() => { setExporting(false); setExported(true); setTimeout(() => setExported(false), 3000); }, 2500);
    };

    const pass = CHECKS.filter(c => c.status === "pass").length;
    const warn = CHECKS.filter(c => c.status === "warn").length;
    const pending = CHECKS.filter(c => c.status === "pending").length;
    const score = Math.round((pass / CHECKS.length) * 100);

    return (
        <div style={{ height: "100%", display: "flex", flexDirection: "column", overflow: "hidden" }}>

            {/* Header */}
            <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", padding: "14px 24px", borderBottom: "1.5px solid #E8E4DC", background: "#fff", flexShrink: 0 }}>
                <div>
                    <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
                        <h1 style={{ fontSize: 17, fontWeight: 900, color: "#0D0D0D", fontFamily: "'Plus Jakarta Sans',sans-serif", letterSpacing: "-.02em" }}>Compliance Center</h1>
                        <span style={{ fontSize: 11, fontWeight: 700, padding: "3px 9px", borderRadius: 999, background: "#F0FDF4", color: "#166534", border: "1px solid #BBF7D0" }}>Score: {score}%</span>
                    </div>
                    <p style={{ fontSize: 12, color: "#A8A49C", marginTop: 3 }}>Security compliance overview, data exports, retention policies, and GDPR controls</p>
                </div>
            </div>

            {/* Tab bar */}
            <div style={{ display: "flex", gap: 6, padding: "10px 24px", borderBottom: "1.5px solid #E8E4DC", background: "#fff", flexShrink: 0 }}>
                {([["overview", "Overview"], ["export", "Data Export"], ["retention", "Retention"], ["gdpr", "GDPR / Privacy"]] as [TabId, string][]).map(([id, label]) => (
                    <TabBtn key={id} id={id} label={label} active={tab} onClick={setTab} />
                ))}
            </div>

            <div style={{ flex: 1, overflowY: "auto", padding: 24, display: "flex", flexDirection: "column", gap: 16 }}>

                {/* ── OVERVIEW ── */}
                {tab === "overview" && (<>
                    {/* Score cards */}
                    <div style={{ display: "grid", gridTemplateColumns: "repeat(3,1fr)", gap: 14 }}>
                        {[
                            { val: pass, unit: "checks", label: "Passing", bg: "#F0FDF4", border: "#BBF7D0", color: "#16A34A" },
                            { val: warn, unit: "issues", label: "Warnings", bg: "#FFFBEB", border: "#FDE68A", color: "#D97706" },
                            { val: pending, unit: "items", label: "Pending", bg: "#EEF2FF", border: "#C7D2FE", color: "#4338CA" },
                        ].map(s => (
                            <div key={s.label} style={{ ...CARD, padding: "20px 24px", background: s.bg, borderColor: s.border }}>
                                <div style={{ fontSize: 36, fontWeight: 900, color: s.color, fontFamily: "'Plus Jakarta Sans',sans-serif", lineHeight: 1 }}>{s.val}</div>
                                <div style={{ fontSize: 13, color: s.color, fontWeight: 600, marginTop: 6, opacity: .8 }}>{s.label} {s.unit}</div>
                            </div>
                        ))}
                    </div>

                    {/* Checklist */}
                    <div style={{ ...CARD, overflow: "hidden" }}>
                        <div style={{ padding: "13px 20px", borderBottom: "1.5px solid #E8E4DC", background: "#F5F0E8" }}>
                            <h3 style={{ fontSize: 14, fontWeight: 800, color: "#0D0D0D", fontFamily: "'Plus Jakarta Sans',sans-serif" }}>Security Checklist</h3>
                        </div>
                        {CHECKS.map((c, i) => (
                            <div key={c.label}
                                style={{ display: "flex", alignItems: "center", gap: 14, padding: "12px 20px", borderBottom: i < CHECKS.length - 1 ? "1px solid #F0EBE3" : "none", transition: "background .15s" }}
                                onMouseEnter={e => (e.currentTarget as HTMLElement).style.background = "#FAFAF7"}
                                onMouseLeave={e => (e.currentTarget as HTMLElement).style.background = "transparent"}>
                                <div style={{
                                    width: 26, height: 26, borderRadius: 8, flexShrink: 0, display: "flex", alignItems: "center", justifyContent: "center",
                                    background: c.status === "pass" ? "#F0FDF4" : c.status === "warn" ? "#FFFBEB" : "#EEF2FF",
                                    border: `1.5px solid ${c.status === "pass" ? "#BBF7D0" : c.status === "warn" ? "#FDE68A" : "#C7D2FE"}`,
                                }}>
                                    {c.status === "pass" && <Check size={13} style={{ color: "#16A34A" }} />}
                                    {c.status === "warn" && <AlertTriangle size={11} style={{ color: "#D97706" }} />}
                                    {c.status === "pending" && <Clock size={11} style={{ color: "#4338CA" }} />}
                                </div>
                                <div style={{ flex: 1 }}>
                                    <div style={{ fontSize: 13, fontWeight: 700, color: "#0D0D0D", marginBottom: 2 }}>{c.label}</div>
                                    <div style={{ fontSize: 11, color: "#A8A49C" }}>{c.detail}</div>
                                </div>
                                <span style={{
                                    fontSize: 10, fontWeight: 700, padding: "2px 8px", borderRadius: 999,
                                    background: c.status === "pass" ? "#F0FDF4" : c.status === "warn" ? "#FFFBEB" : "#EEF2FF",
                                    color: c.status === "pass" ? "#16A34A" : c.status === "warn" ? "#D97706" : "#4338CA",
                                    border: `1px solid ${c.status === "pass" ? "#BBF7D0" : c.status === "warn" ? "#FDE68A" : "#C7D2FE"}`,
                                }}>
                                    {c.status.charAt(0).toUpperCase() + c.status.slice(1)}
                                </span>
                            </div>
                        ))}
                    </div>
                </>)}

                {/* ── DATA EXPORT ── */}
                {tab === "export" && (<>
                    <div style={{ ...CARD, padding: 24 }}>
                        <div style={{ display: "flex", alignItems: "center", gap: 12, marginBottom: 14 }}>
                            <Archive size={18} style={{ color: "#6B675E" }} />
                            <h3 style={{ fontSize: 15, fontWeight: 800, color: "#0D0D0D", fontFamily: "'Plus Jakarta Sans',sans-serif" }}>Full Workspace Export</h3>
                        </div>
                        <p style={{ fontSize: 13, color: "#6B675E", lineHeight: 1.7, marginBottom: 20 }}>
                            Export an encrypted archive of all workspace data: messages, tasks, vault files, and audit logs. The export is a JSON bundle encrypted with AES-256-GCM using your workspace key. Only workspace members with the workspace key can decrypt it.
                        </p>
                        <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr 1fr", gap: 10, marginBottom: 18 }}>
                            {[
                                { icon: FileText, label: "Messages", count: "2,417 encrypted" },
                                { icon: Lock, label: "Files", count: "23 vault items" },
                                { icon: Archive, label: "Audit Log", count: "847 entries" },
                            ].map(item => (
                                <div key={item.label} style={{ padding: "14px 16px", borderRadius: 12, background: "#F5F0E8", border: "1.5px solid #E8E4DC", display: "flex", flexDirection: "column", gap: 8 }}>
                                    <item.icon size={16} style={{ color: "#6B675E" }} />
                                    <div style={{ fontSize: 12, fontWeight: 700, color: "#0D0D0D" }}>{item.label}</div>
                                    <div style={{ fontSize: 11, color: "#A8A49C" }}>{item.count}</div>
