                                <h3 style={{ fontSize: 15, fontWeight: 800, color: "#0D0D0D", fontFamily: "'Plus Jakarta Sans',sans-serif" }}>GDPR & Privacy Controls</h3>
                            </div>
                            <p style={{ fontSize: 13, color: "#6B675E", lineHeight: 1.7 }}>
