                                        <item.icon size={17} style={{ color: "#6B675E" }} />
                                    </div>
                                    <div>
                                        <div style={{ fontSize: 14, fontWeight: 800, color: "#0D0D0D", marginBottom: 4, fontFamily: "'Plus Jakarta Sans',sans-serif" }}>{item.title}</div>
