                                    <button style={{ width: 32, height: 32, borderRadius: 8, border: "1.5px solid #FECACA", background: "#FEE2E2", display: "flex", alignItems: "center", justifyContent: "center", cursor: "pointer", color: "#DC2626" }}><Trash2 size={13} /></button>
