                        </div>
                        <pre style={{ fontFamily: "monospace", fontSize: 12, color: "#2D2D2D", background: "#F5F0E8", border: "1.5px solid #E8E4DC", borderRadius: 10, padding: 16, overflow: "auto", lineHeight: 1.65, margin: 0 }}>{SAMPLE_PAYLOAD}</pre>
