                {/* ── API Keys ── */}
                {tab === "api" && (<>
                    <div style={{ display: "flex", justifyContent: "flex-end" }}>
                        <button className="btn-primary"><Plus size={14} />Create API Key</button>
                    </div>

                    <div style={{ ...CARD, overflow: "hidden" }}>
                        {API_KEYS.map((k, i) => (
