                                        <button onClick={() => { setCopied(k.name); setTimeout(() => setCopied(""), 2000); }}
                                            style={{ display: "flex", alignItems: "center", gap: 5, padding: "5px 10px", borderRadius: 8, border: "1.5px solid #E8E4DC", background: "#fff", fontSize: 12, fontWeight: 600, color: "#0D0D0D", cursor: "pointer" }}>
                                            {copied === k.name ? <><CheckCheck size={12} style={{ color: "#16A34A" }} />Copied</> : <><Copy size={12} />Copy</>}
                                        </button>
                                        <button style={{ display: "flex", alignItems: "center", gap: 5, padding: "5px 10px", borderRadius: 8, border: "1.5px solid #FECACA", background: "#FEE2E2", fontSize: 12, fontWeight: 600, color: "#DC2626", cursor: "pointer" }}>
                                            <Trash2 size={12} />Revoke
                                        </button>
                                    </div>
                                </div>
                                <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 8 }}>
                                    <code style={{ fontSize: 12, fontFamily: "monospace", color: "#9333EA", background: "#F5F3FF", border: "1px solid #DDD6FE", padding: "3px 10px", borderRadius: 6 }}>
                                        {showKey[k.name] ? `${k.prefix}...full_key_hidden` : `${k.prefix}••••••••••••`}
                                    </code>
                                    <button onClick={() => setShowKey(p => ({ ...p, [k.name]: !p[k.name] }))}
                                        style={{ border: "none", background: "none", cursor: "pointer", color: "#A8A49C", padding: 4 }}>
                                        {showKey[k.name] ? <EyeOff size={13} /> : <Eye size={13} />}
                                    </button>
                                </div>
                                <div style={{ display: "flex", gap: 14, fontSize: 11, color: "#A8A49C" }}>
                                    <span>Created: {k.created}</span>
                                    <span>Last used: {k.lastUsed}</span>
                                    <span>Scope: <code style={{ color: "#4F63FF", fontFamily: "monospace" }}>{k.scope}</code></span>
                                </div>
                            </div>
                        ))}
                    </div>

                    <div style={{ background: "#FFFBEB", border: "1.5px solid #FDE68A", borderRadius: 12, padding: "11px 16px", fontSize: 12, color: "#92400E", display: "flex", gap: 10 }}>
                        <span style={{ flexShrink: 0, fontWeight: 700 }}>⚠</span>
                        API keys only access metadata. Message/file content requires client-side decryption with member keypairs — not accessible via API.
                    </div>
                </>)}
            </div>
        </div>
    );
}

"use client";
import { useState } from "react";
import {
    KeyRound, Shield, RefreshCw, Download, Eye, EyeOff,
    Trash2, Check, AlertTriangle, Lock, Copy, CheckCheck,
    Smartphone, Clock, Fingerprint,
} from "lucide-react";
import { useKeys, useUser } from "@/lib/hooks";

const BACKUP_CODES = ["XKQZ-7M2T", "BNPR-4WJH", "CLVS-9YDK", "FMTG-3RAE", "HWQP-6NLX", "JCZB-8SUV", "KDYR-2GFT", "MPWN-5EQJ"];

const CARD: React.CSSProperties = { background: "#fff", borderRadius: 16, border: "1.5px solid #E8E4DC", padding: 22 };

function SectionHead({ icon, title, sub }: { icon: React.ReactNode; title: string; sub: string }) {
    return (
        <div style={{ display: "flex", alignItems: "flex-start", gap: 14, marginBottom: 18 }}>
            <div style={{ width: 42, height: 42, borderRadius: 13, background: "#F5F0E8", border: "1.5px solid #E8E4DC", display: "flex", alignItems: "center", justifyContent: "center", flexShrink: 0 }}>{icon}</div>
            <div>
                <h3 style={{ fontSize: 15, fontWeight: 800, color: "#0D0D0D", fontFamily: "'Plus Jakarta Sans',sans-serif", marginBottom: 3 }}>{title}</h3>
                <p style={{ fontSize: 12, color: "#A8A49C" }}>{sub}</p>
            </div>
        </div>
    );
}

export default function KeysPage() {
    const { user, profile } = useUser();
    const { keys, loading, rotateKey } = useKeys();
    const [showBackup, setShowBackup] = useState(false);
    const [rotating, setRotating] = useState(false);
    const [copied, setCopied] = useState(false);

    const activeWorkspaceKey = keys.find(k => k.status === "active" && k.name === "primary-workspace-key");

    const handleRotate = async () => {
        if (!activeWorkspaceKey || !user || profile?.role !== "owner" && profile?.role !== "admin") return;
        setRotating(true);
        await rotateKey(activeWorkspaceKey.id, user.id);
        setRotating(false);
    };

    const copyAll = () => { setCopied(true); setTimeout(() => setCopied(false), 2000); };

    const isAdmin = profile?.role === "owner" || profile?.role === "admin";

    return (
        <div style={{ height: "100%", display: "flex", flexDirection: "column", overflow: "hidden" }}>
            {/* Header */}
            <div style={{ padding: "14px 24px", borderBottom: "1.5px solid #E8E4DC", background: "#fff", flexShrink: 0 }}>
                <h1 style={{ fontSize: 17, fontWeight: 900, color: "#0D0D0D", fontFamily: "'Plus Jakarta Sans',sans-serif", letterSpacing: "-.02em" }}>Key Management</h1>
                <p style={{ fontSize: 12, color: "#A8A49C", marginTop: 2 }}>Manage your cryptographic identity and workspace encryption keys</p>
            </div>

            <div style={{ flex: 1, overflowY: "auto", padding: 24, display: "flex", flexDirection: "column", gap: 16 }}>

                {/* Keypairs */}
                <div style={CARD}>
                    <SectionHead icon={<Fingerprint size={19} style={{ color: "#0D0D0D" }} />} title="Your Keypairs" sub="Generated locally in your browser on registration. Private keys never leave your device." />
                    <div style={{ display: "flex", flexDirection: "column", gap: 10 }}>
                        {[
                            { label: "Ed25519 Signing Key", purpose: "Message authentication & identity", created: "2026-01-12", fp: "6A:2F:C3:B9:E1:77:D4:82:FA:3C:90:1E:57:4B:AA:D6" },
                            { label: "X25519 Key Exchange", purpose: "Deriving shared session secrets (ECDH)", created: "2026-01-12", fp: "B4:91:5D:28:C7:FF:39:60:2A:63:D5:88:1B:E4:47:93" },
                        ].map(k => (
                            <div key={k.label} style={{ padding: "14px 16px", borderRadius: 12, background: "#F5F0E8", border: "1.5px solid #E8E4DC" }}>
                                <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", marginBottom: 6 }}>
                                    <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
                                        <Lock size={12} style={{ color: "#2E7D32" }} />
                                        <span style={{ fontSize: 13, fontWeight: 700, color: "#0D0D0D" }}>{k.label}</span>
                                    </div>
                                    <span style={{ fontSize: 11, color: "#A8A49C", display: "flex", alignItems: "center", gap: 4 }}><Clock size={10} />Created {k.created}</span>
                                </div>
                                <p style={{ fontSize: 12, color: "#A8A49C", marginBottom: 8 }}>{k.purpose}</p>
                                <div style={{ padding: "6px 12px", borderRadius: 8, background: "#EEF2FF", border: "1px solid #C7D2FE" }}>
                                    <span style={{ fontSize: 11, fontFamily: "monospace", color: "#4F63FF", letterSpacing: ".04em" }}>FP: {k.fp}</span>
                                </div>
                            </div>
                        ))}
                    </div>
                </div>

                {/* Key rotation */}
                {isAdmin && (
                    <div style={CARD}>
                        <SectionHead icon={<RefreshCw size={19} style={{ color: "#0D0D0D" }} />} title="Workspace Key Rotation" sub="Rotate the AES-256-GCM workspace key. All member keys will be re-wrapped automatically." />

                        <div style={{ padding: "13px 16px", borderRadius: 12, background: "#F5F0E8", border: "1.5px solid #E8E4DC", marginBottom: 12, display: "flex", alignItems: "center", justifyContent: "space-between" }}>
                            <div>
                                <p style={{ fontSize: 13, fontWeight: 700, color: "#0D0D0D" }}>Current workspace key</p>
                                <p style={{ fontSize: 11, color: "#A8A49C", marginTop: 2 }}>
                                    {loading ? "Loading..." : activeWorkspaceKey ? `AES-256-GCM · Version ${activeWorkspaceKey.version} · Created ${new Date(activeWorkspaceKey.created_at).toLocaleDateString()}` : "No active key found"}
                                </p>
                            </div>
                            <span style={{ fontSize: 11, fontWeight: 700, padding: "3px 10px", borderRadius: 999, background: "#F0FDF4", color: "#166534", border: "1px solid #BBF7D0", display: "flex", alignItems: "center", gap: 5 }}>
                                <Check size={10} />Active (v{activeWorkspaceKey?.version || 0})
                            </span>
                        </div>

                        <div style={{ padding: "11px 14px", borderRadius: 10, background: "#FFFBEB", border: "1px solid #FDE68A", marginBottom: 14, display: "flex", gap: 10 }}>
                            <AlertTriangle size={14} style={{ color: "#D97706", flexShrink: 0, marginTop: 2 }} />
                            <p style={{ fontSize: 12, color: "#92400E", lineHeight: 1.65 }}>Rotation generates a new AES-256-GCM key, re-encrypts all member key wraps, and marks the old key deprecated. All active sessions will re-key on next message.</p>
                        </div>

                        <button className="btn-primary" onClick={handleRotate} disabled={rotating || !activeWorkspaceKey || loading} style={{ width: "fit-content" }}>
                            {rotating ? <><span style={{ width: 14, height: 14, borderRadius: "50%", border: "2px solid rgba(13,13,13,.2)", borderTopColor: "#0D0D0D", animation: "spin 1s linear infinite", display: "inline-block" }} />Rotating keys…</>
                                : <><RefreshCw size={14} />Rotate Workspace Key</>}
                        </button>

                        {keys.filter(k => k.status === "rotated").length > 0 && (
                            <div style={{ marginTop: 20 }}>
                                <p style={{ fontSize: 12, fontWeight: 700, color: "#0D0D0D", marginBottom: 10 }}>Rotated Keys (Deprecated)</p>
                                <div style={{ display: "flex", flexDirection: "column", gap: 4 }}>
                                    {keys.filter(k => k.status === "rotated").map(k => (
                                        <div key={k.id} style={{ fontSize: 11, color: "#A8A49C", display: "flex", alignItems: "center", gap: 8 }}>
                                            <span style={{ width: 6, height: 6, borderRadius: "50%", background: "#E8E4DC" }} />
                                            Version {k.version} — Rotated {new Date(k.rotated_at || "").toLocaleDateString()}
                                        </div>
                                    ))}
                                </div>
                            </div>
                        )}
                    </div>
                )}

                {/* Backup codes */}
                <div style={CARD}>
                    <SectionHead icon={<Shield size={19} style={{ color: "#0D0D0D" }} />} title="Backup Codes" sub="One-time codes for emergency access if you lose your device and 2FA app." />

                    <div style={{ display: "flex", gap: 8, marginBottom: 14 }}>
                        <button onClick={() => setShowBackup(!showBackup)} style={{ display: "flex", alignItems: "center", gap: 7, padding: "8px 14px", borderRadius: 10, border: "1.5px solid #E8E4DC", background: "#fff", fontSize: 13, fontWeight: 600, color: "#0D0D0D", cursor: "pointer" }}>
                            {showBackup ? <EyeOff size={14} /> : <Eye size={14} />}
                            {showBackup ? "Hide codes" : "Reveal backup codes"}
                        </button>
                        {showBackup && (
                            <button onClick={copyAll} style={{ display: "flex", alignItems: "center", gap: 7, padding: "8px 14px", borderRadius: 10, border: "1.5px solid #E8E4DC", background: "#fff", fontSize: 13, fontWeight: 600, color: "#0D0D0D", cursor: "pointer" }}>
                                {copied ? <><CheckCheck size={14} style={{ color: "#16A34A" }} />Copied!</> : <><Copy size={14} />Copy all</>}
                            </button>
                        )}
                    </div>

                    <div style={{ display: "grid", gridTemplateColumns: "repeat(4,1fr)", gap: 8 }}>
                        {BACKUP_CODES.map(code => (
                            <div key={code} style={{ padding: "10px 12px", borderRadius: 10, textAlign: "center", background: "#F5F0E8", border: "1.5px solid #E8E4DC", fontFamily: "monospace", fontSize: 13, fontWeight: 700, color: showBackup ? "#0D0D0D" : "#C8C4BC", filter: showBackup ? "none" : "blur(5px)", userSelect: showBackup ? "text" : "none", transition: "all .3s" }}>
                                {showBackup ? code : "••••-••••"}
                            </div>
                        ))}
                    </div>
                    <p style={{ fontSize: 11, color: "#A8A49C", marginTop: 10 }}>Each code can only be used once · Store securely offline</p>
                </div>

                {/* Export */}
                <div style={CARD}>
                    <SectionHead icon={<Download size={19} style={{ color: "#0D0D0D" }} />} title="Key Export & Backup" sub="Export an encrypted backup of your private keys. Required to restore access on a new device." />
                    <div style={{ display: "flex", alignItems: "center", gap: 12 }}>
                        <button style={{ display: "flex", alignItems: "center", gap: 7, padding: "9px 16px", borderRadius: 10, border: "1.5px solid #E8E4DC", background: "#fff", fontSize: 13, fontWeight: 600, color: "#0D0D0D", cursor: "pointer" }}>
                            <Download size={14} /> Export Encrypted Key Bundle
                        </button>
                        <span style={{ fontSize: 12, color: "#A8A49C", fontFamily: "monospace", display: "flex", alignItems: "center", gap: 5 }}>
                            <Lock size={11} style={{ color: "#2E7D32" }} />AES-256-GCM encrypted with your passphrase
                        </span>
                    </div>
                </div>

                {/* Trusted devices */}
                <div style={CARD}>
                    <SectionHead icon={<Smartphone size={19} style={{ color: "#0D0D0D" }} />} title="Trusted Devices" sub="Devices approved to access your CipherDesk keys." />
                    <div style={{ display: "flex", flexDirection: "column", gap: 10 }}>
                        {[
                            { name: "MacBook Pro 14\"", os: "macOS 14.4", ip: "10.0.1.42", last: "Now", current: true },
                            { name: "iPhone 15 Pro", os: "iOS 17.3", ip: "10.0.1.67", last: "2h ago", current: false },
                            { name: "Windows PC", os: "Windows 11", ip: "10.0.1.88", last: "3 days ago", current: false },
                        ].map(dev => (
                            <div key={dev.name} style={{ padding: "12px 16px", borderRadius: 12, background: "#F5F0E8", border: `1.5px solid ${dev.current ? "#AAEF45" : "#E8E4DC"}`, display: "flex", alignItems: "center", justifyContent: "space-between" }}>
                                <div>
                                    <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 3 }}>
                                        <span style={{ fontSize: 13, fontWeight: 700, color: "#0D0D0D" }}>{dev.name}</span>
                                        {dev.current && <span style={{ fontSize: 10, fontWeight: 700, padding: "2px 7px", borderRadius: 999, background: "#AAEF45", color: "#0D0D0D" }}>This device</span>}
                                    </div>
                                    <p style={{ fontSize: 12, color: "#A8A49C" }}>{dev.os} · {dev.ip} · Last seen: {dev.last}</p>
                                </div>
                                {!dev.current && (
                                    <button style={{ display: "flex", alignItems: "center", gap: 6, padding: "6px 12px", borderRadius: 9, background: "#FEE2E2", border: "1.5px solid #FECACA", color: "#DC2626", fontSize: 12, fontWeight: 700, cursor: "pointer" }}>
                                        <Trash2 size={12} />Revoke
                                    </button>
                                )}
                            </div>
                        ))}
                    </div>
                </div>
            </div>
        </div>
    );
}

"use client";

import Link from "next/link";
import { usePathname } from "next/navigation";
import { useState } from "react";
import {
    Shield, MessageSquare, CheckSquare, FolderLock,
    Settings, Plus, Hash, Lock, Search, Bell, ChevronDown, Sparkles,
    Users, ScrollText, KeyRound, BarChart3, Plug, ShieldCheck, LogOut,
} from "lucide-react";
import { useUser, useChannels, useMembers, signOut } from "@/lib/hooks";

const NAV = [
    { icon: MessageSquare, label: "Chat", href: "/app/chat/general", match: "/app/chat" },
    { icon: CheckSquare, label: "Tasks", href: "/app/tasks", match: "/app/tasks" },
    { icon: FolderLock, label: "Vault", href: "/app/vault", match: "/app/vault" },
    { icon: Users, label: "Members", href: "/app/members", match: "/app/members" },
    { icon: Bell, label: "Notifications", href: "/app/notifications", match: "/app/notifications" },
    { icon: ScrollText, label: "Audit Log", href: "/app/audit", match: "/app/audit" },
    { icon: KeyRound, label: "Keys", href: "/app/keys", match: "/app/keys" },
    { icon: BarChart3, label: "Admin", href: "/app/admin", match: "/app/admin" },
    { icon: Plug, label: "Integrations", href: "/app/integrations", match: "/app/integrations" },
    { icon: ShieldCheck, label: "Compliance", href: "/app/compliance", match: "/app/compliance" },
    { icon: Settings, label: "Settings", href: "/app/settings", match: "/app/settings" },
];

export default function AppLayout({ children }: { children: React.ReactNode }) {
    const pathname = usePathname();
    const isChat = pathname.startsWith("/app/chat");
    const isActive = (m: string) => pathname.startsWith(m);
    const { user, profile } = useUser();
    const { channels } = useChannels();
    const { members } = useMembers();

    const initials = profile?.full_name
        ? profile.full_name.split(" ").map((w: string) => w[0]).join("").toUpperCase().slice(0, 2)
        : profile?.email?.slice(0, 2).toUpperCase() ?? "??";
    const workspace = profile?.workspace ?? "My Workspace";

    // Direct Messages = all members except me
    const dms = members.filter(m => m.id !== user?.id).map(m => ({
        id: m.id,
        name: m.full_name || m.email,
        av: m.full_name ? m.full_name.slice(0, 2).toUpperCase() : m.email.slice(0, 2).toUpperCase(),
        online: true // Ideally fetch presence, hardcoding true for visually active UX.
    }));

    /* Channel sidebar (chat) */
    const ChatSidebar = () => (
        <div style={{
            width: 220, flexShrink: 0,
            background: "#fff",
            borderRight: "1px solid var(--grey-2)",
            display: "flex", flexDirection: "column", overflow: "hidden",
        }}>
            {/* Workspace header */}
            <div style={{ padding: "12px 10px", borderBottom: "1px solid var(--grey-2)" }}>
                <button style={{
                    width: "100%", display: "flex", alignItems: "center", justifyContent: "space-between",
                    padding: "8px 10px", borderRadius: 10, background: "transparent",
                    border: "1.5px solid var(--grey-2)", cursor: "pointer",
                    transition: "all .2s",
                }}
                    onMouseEnter={e => (e.currentTarget as HTMLElement).style.background = "var(--grey-1)"}
                    onMouseLeave={e => (e.currentTarget as HTMLElement).style.background = "transparent"}>
                    <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
                        <div style={{ width: 24, height: 24, borderRadius: 7, background: "#0D0D0D", display: "flex", alignItems: "center", justifyContent: "center" }}>
                            <Shield size={12} style={{ color: "#AAEF45" }} />
                        </div>
                        <span style={{ fontSize: 13, fontWeight: 700, fontFamily: "'Plus Jakarta Sans',sans-serif", color: "#0D0D0D" }}>{workspace}</span>
                    </div>
                    <ChevronDown size={13} style={{ color: "#A8A49C" }} />
                </button>
            </div>

            {/* Search */}
            <div style={{ padding: "8px 10px" }}>
                <div style={{
                    display: "flex", alignItems: "center", gap: 8,
                    padding: "7px 12px", borderRadius: 9,
                    background: "var(--grey-1)", border: "1.5px solid var(--grey-2)",
                    fontSize: 13, color: "#A8A49C", cursor: "text",
                }}>
                    <Search size={13} />
                    <span>Search…</span>
                    <span style={{ marginLeft: "auto", fontSize: 10, fontFamily: "monospace", color: "#C8C4BC" }}>⌘K</span>
                </div>
            </div>

            {/* Channel list */}
            <div style={{ flex: 1, overflowY: "auto", padding: "4px 6px" }}>
                {/* Channels */}
                <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", padding: "10px 8px 6px" }}>
                    <span style={{ fontSize: 10, fontWeight: 700, textTransform: "uppercase", letterSpacing: ".08em", color: "#A8A49C" }}>Channels</span>
                    <button style={{ background: "none", border: "none", cursor: "pointer", color: "#A8A49C", padding: 2, borderRadius: 4, transition: "color .15s" }}
                        onMouseEnter={e => (e.currentTarget as HTMLElement).style.color = "#0D0D0D"}
                        onMouseLeave={e => (e.currentTarget as HTMLElement).style.color = "#A8A49C"}>
                        <Plus size={13} />
                    </button>
                </div>

                {channels.map(ch => {
                    const active = pathname === `/app/chat/${ch.name}` || pathname === `/app/chat/${ch.id}`;
                    return (
                        <Link key={ch.id} href={`/app/chat/${ch.name}`} className={`ch-item ${active ? "active" : ""}`}>
                            <Hash size={13} style={{ flexShrink: 0, opacity: .6 }} />
                            <span style={{ flex: 1, overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>{ch.name}</span>
                        </Link>
                    );
                })}

                {/* DMs */}
                <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", padding: "12px 8px 6px" }}>
                    <span style={{ fontSize: 10, fontWeight: 700, textTransform: "uppercase", letterSpacing: ".08em", color: "#A8A49C" }}>Direct</span>
                    <button style={{ background: "none", border: "none", cursor: "pointer", color: "#A8A49C", padding: 2, borderRadius: 4 }}>
                        <Plus size={13} />
                    </button>
                </div>

                {dms.map(dm => {
                    const active = pathname === `/app/chat/${dm.id}`;
                    return (
                        <Link key={dm.id} href={`/app/chat/${dm.id}`} className={`ch-item ${active ? "active" : ""}`}>
                            <div style={{ position: "relative", flexShrink: 0 }}>
                                <div style={{ width: 22, height: 22, borderRadius: 7, background: active ? "#fff" : "#0D0D0D", display: "flex", alignItems: "center", justifyContent: "center", fontSize: 9, fontWeight: 800, color: active ? "#0D0D0D" : "#fff" }}>
                                    {dm.av}
                                </div>
                                {dm.online && (
                                    <div style={{ position: "absolute", bottom: -1, right: -1, width: 7, height: 7, borderRadius: "50%", background: "#2E7D32", border: "2px solid #fff" }} />
                                )}
                            </div>
                            <span style={{ flex: 1, fontSize: 13, overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>{dm.name}</span>
                        </Link>
                    );
                })}
            </div>

            {/* E2E status */}
            <div style={{ padding: "10px", borderTop: "1px solid var(--grey-2)" }}>
                <div style={{
                    display: "flex", alignItems: "center", gap: 8,
                    padding: "7px 12px", borderRadius: 9,
                    background: "#F0FDF4", border: "1px solid #BBF7D0",
                }}>
                    <Lock size={11} style={{ color: "#166534" }} />
                    <span style={{ fontSize: 11, fontFamily: "monospace", color: "#166534", letterSpacing: ".03em" }}>E2E Active</span>
                    <div style={{ marginLeft: "auto", width: 6, height: 6, borderRadius: "50%", background: "#22C55E", animation: "pulse-dot 2s ease-in-out infinite" }} />
                </div>
            </div>
        </div>
    );

    /* Generic sidebar (non-chat pages) */
    const GenericSidebar = () => (
        <div style={{
            width: 220, flexShrink: 0, background: "#fff",
            borderRight: "1px solid var(--grey-2)",
            display: "flex", flexDirection: "column",
        }}>
            <div style={{ padding: "12px 10px", borderBottom: "1px solid var(--grey-2)" }}>
                <div style={{ display: "flex", alignItems: "center", gap: 8, padding: "8px 10px" }}>
                    <div style={{ width: 24, height: 24, borderRadius: 7, background: "#0D0D0D", display: "flex", alignItems: "center", justifyContent: "center" }}>
                        <Shield size={12} style={{ color: "#AAEF45" }} />
                    </div>
                    <span style={{ fontSize: 13, fontWeight: 700, fontFamily: "'Plus Jakarta Sans',sans-serif", color: "#0D0D0D" }}>{workspace}</span>
                </div>
            </div>
            <div style={{ flex: 1 }} />
            <div style={{ padding: "10px", borderTop: "1px solid var(--grey-2)" }}>
                <div style={{ display: "flex", alignItems: "center", gap: 8, padding: "7px 12px", borderRadius: 9, background: "#F0FDF4", border: "1px solid #BBF7D0" }}>
                    <Lock size={11} style={{ color: "#166534" }} />
                    <span style={{ fontSize: 11, fontFamily: "monospace", color: "#166634" }}>E2E Active</span>
                    <div style={{ marginLeft: "auto", width: 6, height: 6, borderRadius: "50%", background: "#22C55E", animation: "pulse-dot 2s ease-in-out infinite" }} />
                </div>
            </div>
        </div>
    );

    return (
        <div style={{ height: "100vh", display: "flex", overflow: "hidden", background: "var(--cream)", fontFamily: "Inter, sans-serif" }}>

            {/* ── Icon Rail ── */}
            <aside style={{
                width: 60, flexShrink: 0,
                background: "#fff",
                borderRight: "1px solid var(--grey-2)",
                display: "flex", flexDirection: "column", alignItems: "center",
                padding: "12px 0 10px", gap: 4, zIndex: 20,
            }}>
                {/* Logo */}
                <Link href="/" style={{
                    width: 36, height: 36, borderRadius: 10, marginBottom: 8,
                    background: "#0D0D0D",
                    display: "flex", alignItems: "center", justifyContent: "center",
                    transition: "transform .2s", textDecoration: "none",
                }}
                    onMouseEnter={e => (e.currentTarget as HTMLElement).style.transform = "scale(1.08)"}
                    onMouseLeave={e => (e.currentTarget as HTMLElement).style.transform = "scale(1)"}>
                    <Shield size={16} style={{ color: "#AAEF45" }} />
                </Link>

                <div style={{ width: 28, height: 1, background: "var(--grey-2)", marginBottom: 2 }} />

                {/* Nav items */}
                {NAV.map(item => {
                    const active = isActive(item.match);
                    return (
                        <Link key={item.label} href={item.href} title={item.label}
                            style={{
                                width: 38, height: 38, borderRadius: 10,
                                display: "flex", alignItems: "center", justifyContent: "center",
                                color: active ? "#fff" : "#A8A49C",
                                background: active ? "#0D0D0D" : "transparent",
                                transition: "all .18s", textDecoration: "none", position: "relative",
                            }}
                            onMouseEnter={e => {
                                if (!active) {
                                    (e.currentTarget as HTMLElement).style.background = "var(--grey-1)";
                                    (e.currentTarget as HTMLElement).style.color = "#0D0D0D";
                                }
                            }}
                            onMouseLeave={e => {
                                if (!active) {
                                    (e.currentTarget as HTMLElement).style.background = "transparent";
                                    (e.currentTarget as HTMLElement).style.color = "#A8A49C";
                                }
                            }}>
                            <item.icon size={17} />
                        </Link>
                    );
                })}

                <div style={{ flex: 1 }} />

                {/* AI */}
                <Link href="/app/ai" title="AI Digest (Pro)"
                    style={{
                        width: 38, height: 38, borderRadius: 10,
                        display: "flex", alignItems: "center", justifyContent: "center",
                        color: isActive("/app/ai") ? "#0D0D0D" : "#6B675E",
                        background: isActive("/app/ai") ? "#AAEF45" : "#F5F0E8",
                        border: "1.5px solid var(--grey-2)",
                        transition: "all .2s", textDecoration: "none",
                    }}>
                    <Sparkles size={16} />
                </Link>

                {/* Avatar + sign out */}
                <div style={{ position: "relative" }}>
                    <div style={{
                        width: 34, height: 34, borderRadius: 9, marginTop: 4,
                        background: "#AAEF45",
                        display: "flex", alignItems: "center", justifyContent: "center",
                        fontSize: 12, fontWeight: 800, color: "#0D0D0D", cursor: "pointer",
                        transition: "transform .2s",
                    }}
                        title="Sign out"
                        onClick={() => signOut()}
                        onMouseEnter={e => { (e.currentTarget as HTMLElement).style.transform = "scale(1.08)"; }}
                        onMouseLeave={e => { (e.currentTarget as HTMLElement).style.transform = "scale(1)"; }}>
                        {initials}
                    </div>
                </div>
            </aside>

            {/* ── Channel/Context Sidebar ── */}
            {isChat ? <ChatSidebar /> : <GenericSidebar />}

            {/* ── Main area ── */}
            <main style={{ flex: 1, overflow: "hidden", display: "flex", flexDirection: "column", background: "var(--grey-1)" }}>
                {children}
            </main>
        </div>
    );
}

"use client";
import { useState } from "react";
import {
    Users, UserPlus, Shield, Lock, KeyRound, Check, MoreHorizontal,
    Crown, ShieldCheck, Mail, Clock, X, Copy, CheckCheck,
} from "lucide-react";
import { useMembers, useUser, type Profile } from "@/lib/hooks";

type Role = "owner" | "admin" | "member";

const ROLE_CFG: Record<Role, { label: string; icon: React.ElementType; bg: string; color: string }> = {
    owner: { label: "Owner", icon: Crown, bg: "#FEF9C3", color: "#854D0E" },
    admin: { label: "Admin", icon: ShieldCheck, bg: "#EEF2FF", color: "#3730A3" },
    member: { label: "Member", icon: Users, bg: "#F5F0E8", color: "#6B675E" },
};

function RoleBadge({ role }: { role: Role }) {
    const r = (["owner", "admin", "member"].includes(role) ? role : "member") as Role;
    const c = ROLE_CFG[r];
    return (
        <span style={{ display: "inline-flex", alignItems: "center", gap: 5, padding: "3px 10px", borderRadius: 999, fontSize: 11, fontWeight: 700, background: c.bg, color: c.color }}>
            <c.icon size={10} />{c.label}
        </span>
    );
}

function getAvatarBg(id: string) {
    const colors = ["#4F63FF", "#9333EA", "#2E7D32", "#D97706", "#DC2626", "#0891B2"];
    let hash = 0;
    for (let i = 0; i < id.length; i++) hash = id.charCodeAt(i) + ((hash << 5) - hash);
    return colors[Math.abs(hash) % colors.length];
}

export default function MembersPage() {
    const { user } = useUser();
    const { members, loading, updateRole } = useMembers();

    const [inviteOpen, setInviteOpen] = useState(false);
    const [inviteEmail, setInviteEmail] = useState("");
    const [inviteRole, setInviteRole] = useState<Role>("member");
    const [inviteSent, setInviteSent] = useState(false);
    const [linkCopied, setLinkCopied] = useState(false);

    const handleInvite = (e: React.FormEvent) => {
        e.preventDefault();
        setInviteSent(true);
        // In a real app, this would call supabase API to send magic link
        setTimeout(() => { setInviteOpen(false); setInviteSent(false); setInviteEmail(""); }, 2000);
    };
    const copyLink = () => { setLinkCopied(true); setTimeout(() => setLinkCopied(false), 2000); };

    return (
        <div style={{ height: "100%", display: "flex", flexDirection: "column", overflow: "hidden" }}>

            {/* Header */}
            <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", padding: "14px 24px", borderBottom: "1.5px solid #E8E4DC", background: "#fff", flexShrink: 0 }}>
                <div>
                    <h1 style={{ fontSize: 17, fontWeight: 900, color: "#0D0D0D", fontFamily: "'Plus Jakarta Sans',sans-serif", letterSpacing: "-.02em" }}>Team Members</h1>
                    <p style={{ fontSize: 12, color: "#A8A49C", marginTop: 2 }}>Manage team access · All crypto keys are verified client-side</p>
                </div>
                <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
                    {!loading && <span style={{ fontSize: 13, color: "#A8A49C", marginRight: 10 }}>{members.length} members</span>}
                    <button className="btn-primary" onClick={() => setInviteOpen(true)}>
                        <UserPlus size={15} /> Invite Member
                    </button>
                </div>
            </div>

            {/* Body */}
            <div style={{ flex: 1, overflowY: "auto", padding: 24, display: "flex", flexDirection: "column", gap: 16 }}>

                {/* Plan bar */}
                <div style={{ background: "#fff", border: "1.5px solid #E8E4DC", borderRadius: 14, padding: "13px 18px", display: "flex", alignItems: "center", justifyContent: "space-between", flexWrap: "wrap", gap: 12 }}>
                    <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
                        <Lock size={13} style={{ color: "#166534" }} />
                        <span style={{ fontSize: 13, color: "#0D0D0D" }}>Free plan · <strong>{members.length} / 5 members</strong> used · {5 - members.length} seats remaining</span>
                    </div>
                    <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
                        <span style={{ fontSize: 12, color: "#A8A49C" }}>Invite link:</span>
                        <code style={{ fontSize: 11, fontFamily: "monospace", color: "#4F63FF", background: "#EEF2FF", padding: "3px 10px", borderRadius: 6 }}>cipherdesk.io/invite/bf9x2k</code>
                        <button onClick={copyLink} style={{ display: "flex", alignItems: "center", gap: 5, padding: "4px 10px", borderRadius: 7, border: "1.5px solid #E8E4DC", background: "#fff", fontSize: 12, fontWeight: 600, color: "#0D0D0D", cursor: "pointer" }}>
                            {linkCopied ? <><CheckCheck size={12} style={{ color: "#16A34A" }} />Copied!</> : <><Copy size={12} />Copy</>}
                        </button>
                    </div>
                </div>

                {/* Table */}
                <div style={{ background: "#fff", border: "1.5px solid #E8E4DC", borderRadius: 14, overflow: "hidden" }}>
                    {/* Header */}
                    <div style={{ display: "grid", gridTemplateColumns: "1.5fr 150px 120px 110px 40px", padding: "10px 20px", borderBottom: "1.5px solid #E8E4DC", background: "#F5F0E8" }}>
                        {["Member", "Role", "Joined", "Key Ver.", ""].map(h => (
                            <span key={h} style={{ fontSize: 11, fontWeight: 700, color: "#6B675E", textTransform: "uppercase", letterSpacing: ".06em" }}>{h}</span>
                        ))}
                    </div>

                    {loading ? (
                        <div style={{ padding: 40, display: "flex", justifyContent: "center" }}>
                            <div style={{ width: 28, height: 28, borderRadius: "50%", border: "2px solid #E8E4DC", borderTopColor: "#0D0D0D", animation: "spin 1s linear infinite" }} />
                        </div>
                    ) : (members.map((m, i) => {
                        const bg = getAvatarBg(m.id);
                        const initials = m.full_name ? m.full_name.split(" ").map(w => w[0]).join("").toUpperCase().slice(0, 2) : m.email.slice(0, 2).toUpperCase();
                        const isMe = user?.id === m.id;
                        const date = new Date(m.created_at).toLocaleDateString([], { month: "short", day: "numeric", year: "numeric" });

                        return (
                            <div key={m.id}
                                style={{ display: "grid", gridTemplateColumns: "1.5fr 150px 120px 110px 40px", alignItems: "center", padding: "14px 20px", borderBottom: i < members.length - 1 ? "1px solid #F0EBE3" : "none", transition: "background .15s" }}
                                onMouseEnter={e => (e.currentTarget as HTMLElement).style.background = "#FAFAF7"}
                                onMouseLeave={e => (e.currentTarget as HTMLElement).style.background = "transparent"}>

                                <div style={{ display: "flex", alignItems: "center", gap: 12 }}>
                                    <div style={{ position: "relative", flexShrink: 0 }}>
                                        <div style={{ width: 38, height: 38, borderRadius: 11, background: bg, display: "flex", alignItems: "center", justifyContent: "center", fontSize: 13, fontWeight: 800, color: "#fff" }}>{initials}</div>
                                        {isMe && <div style={{ position: "absolute", bottom: -2, right: -2, width: 10, height: 10, borderRadius: "50%", background: "#22C55E", border: "2px solid #fff" }} />}
                                    </div>
                                    <div style={{ minWidth: 0 }}>
                                        <div style={{ fontSize: 13, fontWeight: 700, color: "#0D0D0D", display: "flex", alignItems: "center", gap: 6, overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>
                                            {m.full_name || "Unknown"}
                                            {isMe && <span style={{ fontSize: 9, fontWeight: 800, padding: "2px 5px", borderRadius: 4, background: "#AAEF45", color: "#0D0D0D" }}>YOU</span>}
                                        </div>
                                        <div style={{ fontSize: 12, color: "#A8A49C", overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>{m.email}</div>
                                    </div>
                                </div>

                                <div>
                                    <select style={{ fontSize: 12, background: "transparent", border: "none", outline: "none", cursor: "pointer", color: "#0D0D0D", fontWeight: 700 }}
                                        value={m.role} onChange={e => { if (user) updateRole(m.id, e.target.value, user.id) }} disabled={isMe}>
                                        <option value="member">Member</option>
                                        <option value="admin">Admin</option>
                                        <option value="owner">Owner</option>
                                    </select>
                                </div>

                                <div style={{ display: "flex", alignItems: "center", gap: 5, fontSize: 12, color: "#A8A49C" }}>
                                    <Clock size={11} />{date}
                                </div>

                                <div>
                                    <span style={{ display: "inline-flex", alignItems: "center", gap: 5, fontSize: 11, fontWeight: 700, padding: "3px 9px", borderRadius: 999, background: "#F0FDF4", color: "#166534", border: "1px solid #BBF7D0" }}><ShieldCheck size={10} />Verified</span>
                                </div>

                                <div>{!isMe && m.role !== "owner" && <button style={{ border: "none", background: "none", cursor: "pointer", color: "#C8C4BC", padding: 4 }}><MoreHorizontal size={16} /></button>}</div>
                            </div>
                        );
                    }))}
                </div>

                {/* Key verification info */}
                <div style={{ background: "#F0FDF4", border: "1.5px solid #BBF7D0", borderRadius: 14, padding: "14px 18px", display: "flex", alignItems: "flex-start", gap: 12 }}>
                    <KeyRound size={16} style={{ color: "#166534", flexShrink: 0, marginTop: 1 }} />
                    <div>
                        <p style={{ fontSize: 13, fontWeight: 700, color: "#166534", marginBottom: 4 }}>How key verification works</p>
                        <p style={{ fontSize: 12, color: "#166534", lineHeight: 1.65, opacity: .85 }}>
                            Each member&apos;s Ed25519 public key is verified against a fingerprint displayed in your authenticator app. Compare fingerprints out-of-band (in person or via a secure call) to confirm identity. The server never participates in this verification — it&apos;s purely peer-to-peer.
                        </p>
                    </div>
                </div>
            </div>

            {/* Invite Modal */}
            {inviteOpen && (
                <div style={{ position: "fixed", inset: 0, zIndex: 50, display: "flex", alignItems: "center", justifyContent: "center", background: "rgba(13,13,13,.4)", backdropFilter: "blur(6px)" }}
                    onClick={e => e.target === e.currentTarget && setInviteOpen(false)}>
                    <div style={{ background: "#fff", borderRadius: 20, padding: 28, width: "100%", maxWidth: 440, boxShadow: "0 20px 60px rgba(0,0,0,.15)" }}>
                        <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", marginBottom: 22 }}>
                            <h2 style={{ fontSize: 17, fontWeight: 900, color: "#0D0D0D", fontFamily: "'Plus Jakarta Sans',sans-serif" }}>Invite a team member</h2>
                            <button onClick={() => setInviteOpen(false)} style={{ border: "none", background: "none", cursor: "pointer", color: "#A8A49C", padding: 4 }}><X size={18} /></button>
                        </div>

                        {inviteSent ? (
                            <div style={{ textAlign: "center", padding: "24px 0" }}>
                                <div style={{ width: 56, height: 56, borderRadius: "50%", background: "#AAEF45", display: "flex", alignItems: "center", justifyContent: "center", margin: "0 auto 14px" }}>
                                    <Check size={24} style={{ color: "#0D0D0D" }} />
                                </div>
                                <p style={{ fontSize: 16, fontWeight: 800, color: "#0D0D0D", marginBottom: 6 }}>Invite sent!</p>
                                <p style={{ fontSize: 13, color: "#A8A49C" }}>They&apos;ll receive an encrypted invite link via email.</p>
                            </div>
                        ) : (
                            <form onSubmit={handleInvite} style={{ display: "flex", flexDirection: "column", gap: 16 }}>
                                <div>
                                    <label style={{ display: "block", fontSize: 13, fontWeight: 600, color: "#2D2D2D", marginBottom: 8 }}>Email address</label>
                                    <input type="email" className="input-field" placeholder="colleague@company.com"
                                        value={inviteEmail} onChange={e => setInviteEmail(e.target.value)} required autoFocus />
                                </div>
                                <div>
                                    <label style={{ display: "block", fontSize: 13, fontWeight: 600, color: "#2D2D2D", marginBottom: 8 }}>Role</label>
                                    <select className="input-field" value={inviteRole} onChange={e => setInviteRole(e.target.value as Role)}>
                                        <option value="member">Member — can view and post</option>
                                        <option value="admin">Admin — can manage channels and members</option>
                                    </select>
                                </div>
                                <div style={{ background: "#F0FDF4", border: "1px solid #BBF7D0", borderRadius: 10, padding: "11px 14px", display: "flex", gap: 10 }}>
                                    <Lock size={13} style={{ color: "#166534", flexShrink: 0, marginTop: 1 }} />
                                    <p style={{ fontSize: 12, color: "#166534", lineHeight: 1.55 }}>An encrypted invite link is generated. When they accept, their browser generates a local Ed25519/X25519 keypair. Their private key never leaves their device.</p>
                                </div>
                                <button type="submit" className="btn-primary" style={{ justifyContent: "center", padding: "12px" }}>
                                    <Mail size={15} /> Send Encrypted Invite
                                </button>
                            </form>
                        )}
                    </div>
                </div>
            )}
        </div>
    );
}

