            {task.description && (
                <p style={{ fontSize: 12, color: "#A8A49C", lineHeight: 1.5, marginBottom: 10, display: "-webkit-box", WebkitLineClamp: 2, WebkitBoxOrient: "vertical", overflow: "hidden" }}>{task.description}</p>
            )}

            {/* Bottom */}
