                    <span style={{ fontSize: 11, color: "#6B675E", maxWidth: 80, overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>{displayName}</span>
                </div>
                <div style={{ display: "flex", alignItems: "center", gap: 6 }}>
                    {task.due_date && (
