                            />
                        </div>
                    </div>
                )}

                {step === "done" && (
                    <div className="card text-center space-y-5">
                        <div className="w-16 h-16 rounded-2xl bg-green-500/10 border border-green-500/20 flex items-center justify-center mx-auto">
